files.patch:
@@ -0,0 +1,15 @@
+from {
+  metadata: {
+    version: "1.6.0",
+  },
+  class_uid: 1007,
+  process: {
+    pid: 1234,
+    cmd_line: "command",
+    parent_process: {
+      pid: 5678,
+      cmd_line: "command",
+    }
+  }
+}
+ocsf::apply

@@ -0,0 +1,18 @@
+from {
+  metadata: {
+    version: "1.5.0",
+  },
+  class_uid: 1007,
+  process: {
+    pid: 1234,
+    parent_process: {
+      pid: 5678,
+      // This should be dropped because parent_process_nonrecursive
+      // doesn't have a parent_process field
+      parent_process: {
+        pid: 9999,
+      }
+    }
+  }
+}
+ocsf::apply

@@ -0,0 +1,19 @@
+from {
+  metadata: {
+    version: "1.5.0",
+  },
+  class_uid: 2001,
+  analytic: {
+    name: "Main Analytic",
+    type_id: 1,
+    related_analytics: [
+      {
+        name: "Related Analytic 1",
+        type_id: 2,
+      }
+    ]
+  }
+}
+ocsf::apply
+// Verify related_analytics is accessible
+assert analytic.related_analytics[0].name == "Related Analytic 1"

@@ -0,0 +1,26 @@
+from {
+  metadata: {
+    version: "1.5.0",
+  },
+  class_uid: 2001,
+  analytic: {
+    name: "Main Analytic",
+    type_id: 1,
+    related_analytics: [
+      {
+        name: "Related Analytic 1",
+        type_id: 2,
+        // This should be dropped
+        related_analytics: [
+          {
+            name: "Nested Related",
+            type_id: 3,
+          }
+        ]
+      }
+    ]
+  }
+}
+ocsf::apply
+// Verify nested related_analytics was dropped
+assert not analytic.related_analytics[0].has("related_analytics")
